  ('Email bán hàng', 'email-ban-hang', 'Mẫu email giới thiệu, gửi thông tin và follow-up.', 30),
  ('Follow-up', 'follow-up', 'Mẫu nhắc lại sau báo giá, demo hoặc tư vấn.', 40),
